#include <stdio.h>
#include <stdlib.h>

typedef struct Node{int v; struct Node* nxt;} Node;

Node** adj;
int maxDepth;

void addEdge(int u,int v){
    Node* n=(Node*)malloc(sizeof(Node));
    n->v=v; n->nxt=adj[u]; adj[u]=n;
}

void dfs(int u,int parent,int depth){
    if(depth>maxDepth) maxDepth=depth;
    for(Node* cur=adj[u];cur;cur=cur->nxt){
        int v=cur->v;
        if(v!=parent) dfs(v,u,depth+1);
    }
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n; scanf("%d",&n);
        adj=(Node**)calloc(n+1,sizeof(Node*));
        for(int i=0;i<n-1;i++){
            int u,v; scanf("%d %d",&u,&v);
            addEdge(u,v); addEdge(v,u);
        }
        maxDepth=0;
        dfs(1,-1,0);
        printf("%d\n",maxDepth);
        for(int i=1;i<=n;i++){
            Node* cur=adj[i];
            while(cur){
                Node* tmp=cur; cur=cur->nxt; free(tmp);
            }
        }
        free(adj);
    }
    return 0;
}

