#!/usr/bin/env python3
import sys
sys.setrecursionlimit(200000)

def dfs(u,parent,depth,adj):
    global max_depth
    if depth>max_depth:
        max_depth=depth
    for v in adj[u]:
        if v!=parent:
            dfs(v,u,depth+1,adj)

def main():
    data=sys.stdin.read().strip().split()
    if not data:
        return
    it=iter(data)
    T=int(next(it))
    out=[]
    for _ in range(T):
        n=int(next(it))
        adj=[[] for _ in range(n+1)]
        for _ in range(n-1):
            u=int(next(it)); v=int(next(it))
            adj[u].append(v); adj[v].append(u)
        global max_depth
        max_depth=0
        dfs(1,-1,0,adj)
        out.append(str(max_depth))
    sys.stdout.write('\n'.join(out))

if __name__=='__main__':
    main()

